var API_BASE = '/api/notes';
var API_KEY = 'tb3_notes_api_secret_2026';

var editingId = null;

function mutHeaders() {
  return {
    'Content-Type': 'application/json',
    'X-API-Key': API_KEY
  };
}

async function loadNotes() {
  var res = await fetch(API_BASE);
  var notes = await res.json();
  var list = document.getElementById('notes-list');
  list.innerHTML = '';
  notes.forEach(function(note) {
    var row = document.createElement('div');
    row.className = 'note-card';

    var h3 = document.createElement('h3');
    h3.textContent = note.title;
    row.appendChild(h3);

    var p = document.createElement('p');
    p.textContent = note.content;
    row.appendChild(p);

    var editBtn = document.createElement('button');
    editBtn.className = 'edit-btn';
    editBtn.setAttribute('data-id', String(note.id));
    editBtn.setAttribute('data-title', note.title);
    editBtn.setAttribute('data-content', note.content);
    editBtn.textContent = 'Edit';
    editBtn.addEventListener('click', function() {
      editingId = note.id;
      document.getElementById('note-title').value = note.title;
      document.getElementById('note-content').value = note.content;
    });
    row.appendChild(editBtn);

    var deleteBtn = document.createElement('button');
    deleteBtn.className = 'delete-btn';
    deleteBtn.setAttribute('data-id', String(note.id));
    deleteBtn.textContent = 'Delete';
    deleteBtn.addEventListener('click', async function() {
      await fetch(API_BASE + '/' + note.id, {
        method: 'DELETE',
        headers: mutHeaders()
      });
      await loadNotes();
    });
    row.appendChild(deleteBtn);

    list.appendChild(row);
  });
}

document.getElementById('note-form').addEventListener('submit', async function(e) {
  e.preventDefault();
  var titleEl = document.getElementById('note-title');
  var contentEl = document.getElementById('note-content');
  var title = titleEl.value;
  var content = contentEl.value;

  if (editingId !== null) {
    await fetch(API_BASE + '/' + editingId, {
      method: 'PUT',
      headers: mutHeaders(),
      body: JSON.stringify({ title: title, content: content })
    });
  } else {
    await fetch(API_BASE, {
      method: 'POST',
      headers: mutHeaders(),
      body: JSON.stringify({ title: title, content: content })
    });
  }

  editingId = null;
  titleEl.value = '';
  contentEl.value = '';
  await loadNotes();
});

loadNotes();
